/* eslint-disable @next/next/no-img-element */
import Link from "next/link";

import { ProductCard } from "@/components/ui/ProductCard";
import { getServerLanguage } from "@/lib/server-language";
import {
  getActiveBanners,
  getFeaturedCategories,
  getNewArrivalProducts,
  getOfferProducts,
} from "@/lib/storefront-data";
import { getCategoryName, getMessages, getProductName } from "@/lib/storefront";

export const dynamic = "force-dynamic";

export default async function HomePage() {
  const language = await getServerLanguage();
  const messages = getMessages(language);
  const [banners, categories, offers, newArrivals] = await Promise.all([
    getActiveBanners(),
    getFeaturedCategories(),
    getOfferProducts(8),
    getNewArrivalProducts(8),
  ]);

  const heroBanner = banners[0] ?? null;
  const heroProduct = offers[0] ?? newArrivals[0] ?? null;

  return (
    <div className="space-y-10 lg:space-y-16">
      <section className="section-space pb-4 pt-6 lg:pt-10">
        <div className="grid gap-8 lg:grid-cols-[1.02fr_0.98fr] lg:items-center xl:gap-12">
          <div className={language === "ar" ? "text-right" : "text-left"}>
            <p className="eyebrow">{messages.home.eyebrow}</p>
            <h1 className="mt-5 max-w-3xl text-5xl font-bold leading-[1.05] tracking-tight text-[#1D1D1F] sm:text-6xl xl:text-7xl">
              {messages.home.title}
            </h1>
            <p className="mt-6 max-w-2xl text-lg leading-8 text-slate-500">
              {messages.home.subtitle}
            </p>

            <div className="mt-8 flex flex-wrap gap-3">
              <Link href="/products" className="pill-button-primary">
                {messages.home.browseAll}
              </Link>
              <Link href="/cart" className="pill-button-ghost">
                {messages.nav.cart}
              </Link>
            </div>
          </div>

          <div className="soft-panel overflow-hidden bg-white">
            <div className="grid min-h-[28rem] gap-4 p-5 sm:p-7">
              <div className="grid gap-4 lg:grid-cols-[1.1fr_0.9fr]">
                <div className="relative overflow-hidden rounded-[2rem] bg-slate-50 p-6">
                  <div className={language === "ar" ? "text-right" : "text-left"}>
                    <p className="eyebrow">
                      {heroBanner?.discount ||
                        (language === "ar" ? "اختيار اليوم" : "Today’s pick")}
                    </p>
                    <h2 className="mt-3 text-2xl font-semibold tracking-tight text-[#1D1D1F]">
                      {heroBanner?.title ||
                        (language === "ar" ? "كل ما يحتاجه المنزل" : "Everything your home needs")}
                    </h2>
                    <p className="mt-3 text-sm leading-7 text-slate-500">
                      {heroBanner?.subtitle || messages.home.promoSubtitle}
                    </p>
                  </div>

                  {heroBanner?.image_url ? (
                    <img
                      src={heroBanner.image_url}
                      alt={heroBanner.title}
                      className="mt-6 h-56 w-full rounded-[2rem] object-cover"
                    />
                  ) : heroProduct ? (
                    <img
                      src={heroProduct.image_url}
                      alt={getProductName(heroProduct, language)}
                      className="mt-6 h-56 w-full object-contain"
                    />
                  ) : null}
                </div>

                <div className="rounded-[2rem] bg-[linear-gradient(180deg,#ffffff_0%,#f7faf7_100%)] p-6">
                  {heroProduct ? (
                    <>
                      <p className="eyebrow">{messages.home.discoverFresh}</p>
                      <h3 className="mt-3 text-2xl font-semibold text-[#1D1D1F]">
                        {getProductName(heroProduct, language)}
                      </h3>
                      <p className="mt-4 text-sm leading-7 text-slate-500">
                        {language === "ar"
                          ? "منتج نشط من البيانات الحية، جاهز للإضافة إلى السلة مباشرة."
                          : "An active product from live catalog data, ready to add to cart."}
                      </p>
                      <img
                        src={heroProduct.image_url}
                        alt={getProductName(heroProduct, language)}
                        className="mt-8 h-48 w-full object-contain"
                      />
                    </>
                  ) : (
                    <div className="flex h-full items-center justify-center text-center text-sm text-slate-500">
                      {messages.home.noBanners}
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>
        </div>

        <div className="mt-8 overflow-x-auto pb-2">
          <div className="flex min-w-max gap-3">
            {categories.map((category) => (
              <Link
                key={category.id}
                href={`/category/${category.id}`}
                className="inline-flex min-h-12 items-center gap-3 rounded-full border border-slate-200 bg-white px-5 py-3 text-sm font-medium text-slate-600 transition hover:-translate-y-0.5 hover:border-primary/30 hover:text-[#1D1D1F]"
              >
                <span className="flex h-9 w-9 items-center justify-center rounded-full bg-slate-50 text-base text-primary">
                  {category.icon?.slice(0, 1) || "•"}
                </span>
                <span>{getCategoryName(category, language)}</span>
              </Link>
            ))}
          </div>
        </div>
      </section>

      <section className="section-space py-2">
        <div className="mb-8 flex items-end justify-between gap-4">
          <div className={language === "ar" ? "text-right" : "text-left"}>
            <p className="eyebrow">{messages.home.offers}</p>
            <h2 className="section-heading mt-3">{messages.home.offers}</h2>
          </div>
          <Link href="/products" className="pill-button-ghost">
            {messages.common.viewAll}
          </Link>
        </div>

        {offers.length > 0 ? (
          <div className="grid grid-cols-1 gap-6 md:grid-cols-2 xl:grid-cols-4">
            {offers.slice(0, 8).map((product) => (
              <ProductCard key={product.id} product={product} />
            ))}
          </div>
        ) : (
          <div className="soft-panel px-6 py-14 text-center text-slate-500">
            {messages.home.noOffers}
          </div>
        )}
      </section>

      <section className="section-space py-2">
        <div className="mb-8 flex items-end justify-between gap-4">
          <div className={language === "ar" ? "text-right" : "text-left"}>
            <p className="eyebrow">{messages.home.categories}</p>
            <h2 className="section-heading mt-3">{messages.home.categories}</h2>
          </div>
        </div>

        {categories.length > 0 ? (
          <div className="grid gap-6 md:grid-cols-2 xl:grid-cols-3">
            {categories.map((category) => (
              <Link
                key={category.id}
                href={`/category/${category.id}`}
                className="group overflow-hidden rounded-[2.5rem] bg-white shadow-soft transition duration-300 hover:-translate-y-1 hover:shadow-premium"
              >
                <div className="relative min-h-[22rem] overflow-hidden bg-slate-50 p-6">
                  {category.image_url ? (
                    <img
                      src={category.image_url}
                      alt={getCategoryName(category, language)}
                      className="absolute inset-0 h-full w-full object-cover transition duration-500 group-hover:scale-105"
                    />
                  ) : null}
                  <div className="absolute inset-0 bg-gradient-to-t from-white via-white/80 to-transparent" />
                  <div className="relative mt-28">
                    <span className="inline-flex h-12 w-12 items-center justify-center rounded-full bg-white text-xl text-primary shadow-soft">
                      {category.icon?.slice(0, 1) || "•"}
                    </span>
                    <h3 className="mt-4 text-2xl font-semibold text-[#1D1D1F]">
                      {getCategoryName(category, language)}
                    </h3>
                    <p className="mt-3 max-w-sm text-sm leading-7 text-slate-500">
                      {language === "ar"
                        ? "تجربة تصفح سريعة مع منتجات نشطة فقط من هذا القسم."
                        : "A fast browsing surface with active products only from this category."}
                    </p>
                  </div>
                </div>
              </Link>
            ))}
          </div>
        ) : (
          <div className="soft-panel px-6 py-14 text-center text-slate-500">
            {messages.home.noCategories}
          </div>
        )}
      </section>

      <section className="section-space py-2">
        <div className="overflow-hidden rounded-[2.5rem] bg-[linear-gradient(135deg,#2E7D32_0%,#419b46_100%)] px-6 py-10 text-white shadow-premium sm:px-10 lg:px-14 lg:py-14">
          <div className="grid gap-8 lg:grid-cols-[1fr_auto] lg:items-center">
            <div className={language === "ar" ? "text-right" : "text-left"}>
              <p className="text-xs uppercase tracking-[0.32em] text-white/70">
                {language === "ar" ? "متجر أسرع" : "A faster storefront"}
              </p>
              <h2 className="mt-4 text-3xl font-semibold tracking-tight sm:text-4xl">
                {messages.home.promoTitle}
              </h2>
              <p className="mt-4 max-w-2xl text-base leading-8 text-white/80">
                {messages.home.promoSubtitle}
              </p>
            </div>
            <Link
              href={heroBanner?.link || "/products"}
              className="inline-flex min-h-12 items-center justify-center rounded-full bg-white px-8 py-4 text-sm font-semibold text-[#1D1D1F] transition hover:-translate-y-0.5"
            >
              {messages.home.promoAction}
            </Link>
          </div>
        </div>
      </section>

      <section className="section-space pt-2">
        <div className="mb-8 flex items-end justify-between gap-4">
          <div className={language === "ar" ? "text-right" : "text-left"}>
            <p className="eyebrow">{messages.home.newArrivals}</p>
            <h2 className="section-heading mt-3">{messages.home.newArrivals}</h2>
          </div>
          <Link href="/products?sort=newest" className="pill-button-ghost">
            {messages.common.viewAll}
          </Link>
        </div>

        {newArrivals.length > 0 ? (
          <div className="grid grid-cols-1 gap-6 md:grid-cols-2 xl:grid-cols-4">
            {newArrivals.map((product) => (
              <ProductCard key={product.id} product={product} />
            ))}
          </div>
        ) : (
          <div className="soft-panel px-6 py-14 text-center text-slate-500">
            {language === "ar"
              ? "لا توجد منتجات حديثة حالياً."
              : "No recent products are available right now."}
          </div>
        )}
      </section>
    </div>
  );
}
